  ('fire-eq-eng-moex-01003', 'fire-eq-eng', 'fire-eq-eng-moex-099-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '關於消防機關辦理建築物消防安全設備審查及查驗作業規定，下列何者有誤？', '["消防安全設備設計人無正當理由未會同審查者，得予退件", "變更設計或變更用途，非系統式設備僅變動滅火器、緊急照明燈等簡易設備者，設計人得免配合審查", "竣工現場設置之消防安全設備與原審訖消防圖說之設備位置有異動時，於不影響設備功能及性能之情 形下，得直接修改竣工圖", "消防安全設備測試報告書應由消防器材廠商於各項設備施工完成後依報告書內項目實際測試其性能， 並填寫其測試結果"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:18+00:00", "source_pdf_sha1": "558d9c38d998", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "099080", "c": "601", "s": "200", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規", "year": "099", "exam_name": "099年專技消防設備人員、地政士、專責報關、保險人員、特考中醫、語言治療、聽力考試", "original_question_number": 27, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
