  ('fire-eq-eng-moex-01005', 'fire-eq-eng', 'fire-eq-eng-moex-099-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '關於無窗戶居室，下列何者有誤？', '["有效採光面積未達該居室樓地板面積百分之五", "可直接開向戶外或可通達戶外之有效防火避難構造開口，其高度未達一公尺，寬度未達七十五公分", "可直接開向戶外或可通達戶外之有效防火避難構造開口，為圓型時直徑未達一公尺者", "樓地板面積超過五十平方公尺之居室，其天花板或天花板下方八十公分範圍以內之有效通風面積未達 樓地板面積百分之二"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:18+00:00", "source_pdf_sha1": "558d9c38d998", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "099080", "c": "601", "s": "200", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規", "year": "099", "exam_name": "099年專技消防設備人員、地政士、專責報關、保險人員、特考中醫、語言治療、聽力考試", "original_question_number": 29, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
